#include "VirtualMemory.h"#include "PhysicalMemory.h"#include "algorithm"void VMinitialize(){  for (int i=0; i< PAGE_SIZE; ++i)    {      PMwrite(i, 0);    }}bool search_frame(int parent_frame, uint64_t index_page, int depth,                  uint64_t& parent_frame_res, uint64_t &index_page_res,uint64_t frame_idx){  int res, res2;  int Is5 = 5; // 1  uint64_t  new_res_page, new_frame_res;  new_frame_res = new_res_page = 0;  PMread (parent_frame * PAGE_SIZE + index_page, &res);//  printf("hello\n");  if (res == int(frame_idx))    {      return false;    }  if (depth == TABLES_DEPTH)    {return false;}  else    {      for (int index_loop = 0  ; index_loop < PAGE_SIZE ; index_loop ++)        {          PMread (res * PAGE_SIZE + index_loop, &res2);          if (res2 != 0)            {              Is5 = 10;              if (search_frame (res, index_loop,                          depth + 1,  new_frame_res, new_res_page,                          frame_idx))                {                  parent_frame_res = new_frame_res;                  index_page_res = new_res_page;                  return true;                }            }        }      if (Is5 == 10) {return false;}      else if(Is5 == 5)        {          parent_frame_res = parent_frame;          index_page_res = index_page;          return true;        }    }  return true;}uint64_t unused(int depth, uint64_t frame);uint64_t helper2(int depth, uint64_t frame){  uint64_t current, maximum;  maximum = frame;  int res;  int index_j = 0;  int stam = 0;  while (index_j < PAGE_SIZE) {      PMread(frame * PAGE_SIZE + index_j, &res);      if (res != 0)        {          current = unused(depth +1 , res);          if (current <=  maximum) { stam ++; }          else{              maximum = current;            }        }      index_j++;    }  return maximum;}uint64_t unused(int depth, uint64_t frame){  if (depth != TABLES_DEPTH)    {      return helper2(depth, frame);    }  return frame;}int read_evict_write(uint64_t max_result_parent,uint64_t max_result_index,                     int result ,uint64_t max_result_page){  PMread(max_result_parent * PAGE_SIZE + max_result_index,         &result);  PMevict(result, max_result_page);  PMwrite(max_result_parent *PAGE_SIZE + max_result_index,0);  return  result;}void swapped_page_func(int x,uint64_t n, uint64_t d, uint64_t numofpage,                       uint64_t swapped_pg,uint64_t &max_result_parent,                       uint64_t &max_result_index, uint64_t &max_result_page){  uint16_t new_page_number;  int indexloop = 0;  while(indexloop < PAGE_SIZE)    {      PMread(n * PAGE_SIZE + indexloop , &x);      if (x != 0)        {          uint64_t y;          new_page_number = (numofpage << OFFSET_WIDTH) + indexloop;          if (d + 1 == TABLES_DEPTH) {              if(swapped_pg>=new_page_number)                {                  y = swapped_pg - new_page_number;                  int temp;                  for(int a; a < 7 ; a++)                    {                      temp++;                    }                }              else                {                  y = new_page_number - swapped_pg;                }              uint64_t x = NUM_PAGES - y;              if ((std::min(x, y)) > max_result_page) {                  auto x = n;                  max_result_page = new_page_number;                  max_result_parent = x;                  max_result_index = indexloop;                }            }          else if(d + 1 != TABLES_DEPTH){              swapped_page_func(0,(uint64_t)x, d + 1,              new_page_number, swapped_pg,max_result_parent,              max_result_index, max_result_page);            }        }      indexloop++;    }}int search_maximumleaf (uint64_t swapped_pg){  uint64_t max_result_page = 0, max_result_parent, max_result_index;  int result = 0;  swapped_page_func(0,0,0,0,swapped_pg,max_result_parent,                    max_result_index,max_result_page);  return (read_evict_write(max_result_parent,max_result_index,result,                           max_result_page));}uint64_t find_appropriate(uint64_t original_virtual, uint64_t frame_idx) {  uint64_t res;  int k = 7;  int index_loop;  uint64_t index_page_res, parent_frame_res;  index_page_res = parent_frame_res =0;  for( index_loop = 0 ; index_loop < PAGE_SIZE; index_loop++ ) {      auto x = search_frame(0, index_loop, 1,                            parent_frame_res,index_page_res,frame_idx);      if (x)        {          k= 4;          int final;          PMread (index_page_res + PAGE_SIZE*parent_frame_res ,                  &final);          PMwrite (parent_frame_res * PAGE_SIZE + index_page_res,                   0);          res = final ;        }    }  if ( k == 4)    { return res;}  uint64_t returned_value_increment = unused (0,0) + 1;  if(returned_value_increment < NUM_FRAMES)    {      return returned_value_increment;    }  else{      return search_maximumleaf(original_virtual);    }}int get_address(uint64_t virtualAddress){//  uint64_t offset = virtualAddress % PAGE_SIZE;  uint64_t original_virtual = virtualAddress >>OFFSET_WIDTH;  //WE WANT TO SAVE THE BITS OF THE ADDRESS 0110 - IN THE EXAMPLE  uint64_t bits_array[TABLES_DEPTH];  int index;  for (int i =0; i< TABLES_DEPTH; ++i)    {      uint64_t zero_one = (1 << OFFSET_WIDTH) -1; //0001      index = TABLES_DEPTH - i -1;      bits_array[index] = (virtualAddress >> ((i +1) * OFFSET_WIDTH))&zero_one;    }  int depth_index = 0;  word_t frame_idx = 0; //current index  word_t my_pm_read = 0; //new index  bool okay = true;//  uint64_t appropriate_frame = 0;  while (depth_index < TABLES_DEPTH)    {      PMread((frame_idx * PAGE_SIZE)+bits_array[depth_index],&my_pm_read);      if (!my_pm_read) // my pm read = 0        {          my_pm_read = find_appropriate(original_virtual, frame_idx);          //FIND FRAME! - LETS SUPPOSE THE APPROPRIATE_FRAME IS app_frame;          for (uint64_t i = 0; i < PAGE_SIZE; ++i)            //FILLING THE PAGES OF FRAME 0 WITH ZEROS;            {              PMwrite ((my_pm_read * PAGE_SIZE )+ i, 0);            }          PMwrite ((frame_idx * PAGE_SIZE )+          bits_array[depth_index],my_pm_read);      // WRITE THE NUMBER OF THE FRAME IN THE RAM!          okay = false;        }      frame_idx = my_pm_read;      depth_index++;    }  if (!okay)  //okay = false    {      PMrestore(frame_idx, original_virtual);    }  return frame_idx;}int VMread(uint64_t virtualAddress, word_t* value){  if (virtualAddress > VIRTUAL_MEMORY_SIZE)    {      return 0; //FAILURE    }  else    {      word_t final = get_address(virtualAddress);      uint64_t offset = virtualAddress & ((1<<OFFSET_WIDTH) -1);      uint64_t physical = PAGE_SIZE * final + offset;      PMread(physical,value);      return 1;    }}int VMwrite(uint64_t virtualAddress, word_t value){  if (virtualAddress > VIRTUAL_MEMORY_SIZE)    {      return 0; //FAILURE    }  else    {      word_t final = get_address(virtualAddress);      uint64_t offset = virtualAddress & ((1 << OFFSET_WIDTH) -1);      uint64_t physical = PAGE_SIZE * final + offset;      PMwrite(physical,value);      return 1;    }}